import { ApiPropertyOptional } from "@nestjs/swagger";
import { IsEnum, IsOptional } from "class-validator";

import { PaymentStatus } from "../../../constants/payment-status.ts";
import { StringFieldOptional } from "../../../decorators/field.decorators.ts";

export class UpdatePaymentDto {
  @ApiPropertyOptional({ enum: PaymentStatus })
  @IsEnum(PaymentStatus)
  @IsOptional()
  status?: PaymentStatus;

  @StringFieldOptional({ maxLength: 255 })
  transactionId?: string;

  @StringFieldOptional({ maxLength: 255 })
  gatewayReference?: string;

  @StringFieldOptional({ maxLength: 500 })
  description?: string;

  @StringFieldOptional({ maxLength: 1000 })
  errorMessage?: string;
}
